const tickets = $input.all().map(i => i.json);
const toProcess = tickets.filter(t => {
  const fp = String(t.feedback_processed ?? '').trim().toUpperCase();
  const isUnprocessed = fp === 'FALSE' || fp === '0' || t.feedback_processed === false;
  const feedback = String(t.feedback || t[12] || '').trim().toLowerCase();
  return isUnprocessed && (feedback === 'agree' || feedback === 'disagree');
});
if (toProcess.length === 0) return [{ json: { _skip: true, message: 'No reviewed feedback found', count: 0 } }];
return toProcess.map(t => ({ json: t }));

const reviewedTickets = $input.all().map(item => item.json);
if (reviewedTickets.length === 0) return [{ json: { _skip: true } }];

const now = new Date();
const dateStr = now.toISOString().split('T')[0];
let agreed = 0, disagreed = 0;
const categoryAccuracy = {};
const languageAccuracy = {};
const ticketIdsProcessed = [];

for (const ticket of reviewedTickets) {
  const feedback = (ticket.feedback || ticket[12] || '').toString().trim().toLowerCase();
  const category = ticket.issue_category || ticket[6] || 'Other';
  const language = ticket.language || ticket[10] || 'en';
  const ticketId = ticket.ticket_id || ticket[0] || '';
  const isAgree = feedback === 'agree';
  const isDisagree = feedback === 'disagree';
  if (!isAgree && !isDisagree) continue;
  ticketIdsProcessed.push(ticketId);
  if (isAgree) agreed++; else disagreed++;
  if (!categoryAccuracy[category]) categoryAccuracy[category] = { agreed: 0, disagreed: 0 };
  if (isAgree) categoryAccuracy[category].agreed++; else categoryAccuracy[category].disagreed++;
  if (!languageAccuracy[language]) languageAccuracy[language] = { agreed: 0, disagreed: 0 };
  if (isAgree) languageAccuracy[language].agreed++; else languageAccuracy[language].disagreed++;
}

const totalReviewed = agreed + disagreed;
const accuracyRate = totalReviewed > 0 ? Math.round((agreed / totalReviewed) * 1000) / 1000 : 0;

let worstCategory = 'N/A';
let worstRate = 0;
for (const [cat, data] of Object.entries(categoryAccuracy)) {
  const catTotal = data.agreed + data.disagreed;
  const rate = catTotal > 0 ? data.disagreed / catTotal : 0;
  if (rate > worstRate) { worstRate = rate; worstCategory = cat; }
}

const notes = `Processed ${totalReviewed} tickets. Accuracy: ${Math.round(accuracyRate*100)}%. Worst category: ${worstCategory} (${Math.round(worstRate*100)}% disagreement).`;

const languageRows = Object.entries(languageAccuracy).map(([lang, data]) => {
  const langTotal = data.agreed + data.disagreed;
  const langRate = langTotal > 0 ? Math.round((data.agreed / langTotal) * 1000) / 1000 : 0;
  return { json: { date: dateStr, total_reviewed: langTotal, agreed: data.agreed, disagreed: data.disagreed, accuracy_rate: langRate, worst_category: worstCategory, notes: `Language: ${lang}. ${langTotal} tickets. Accuracy: ${Math.round(langRate*100)}%.`, language: lang, _ticket_ids: [] } };
});

return [{ json: { date: dateStr, total_reviewed: totalReviewed, agreed, disagreed, accuracy_rate: accuracyRate, worst_category: worstCategory, notes, language: 'all', _ticket_ids: ticketIdsProcessed } }, ...languageRows];

// Build list of ticket IDs to mark as processed
const accuracyData = $('Calculate Accuracy').first().json;
const ticketIds = accuracyData._ticket_ids || [];
// Return one item per ticket ID for the update loop
if (ticketIds.length === 0) return [{ json: { _no_updates: true } }];
return ticketIds.map(id => ({ json: { ticket_id: id, feedback_processed: true } }));
